import{_ as a,c as o,o as s,a1 as n}from"./chunks/framework.DILC4Csi.js";const m=JSON.parse('{"title":"Preguntas Frecuentes: Resolución de Problemas de Uso | opencode-plannotator","description":"Aprende a resolver problemas comunes de Plannotator. Domina técnicas de diagnóstico rápido para problemas de puerto ocupado, navegador no abierto, fallos de integración y más.","frontmatter":{"title":"Preguntas Frecuentes: Resolución de Problemas de Uso | opencode-plannotator","sidebarTitle":"Qué hacer si tienes problemas","subtitle":"Preguntas Frecuentes: Resolución de Problemas de Uso","description":"Aprende a resolver problemas comunes de Plannotator. Domina técnicas de diagnóstico rápido para problemas de puerto ocupado, navegador no abierto, fallos de integración y más.","order":4},"headers":[],"relativePath":"es/backnotprop/plannotator/faq/index.md","filePath":"es/backnotprop/plannotator/faq/index.md"}'),r={name:"es/backnotprop/plannotator/faq/index.md"};function t(i,e,l,d,c,p){return s(),o("div",null,[...e[0]||(e[0]=[n(`<h1 id="preguntas-frecuentes" tabindex="-1">Preguntas Frecuentes <a class="header-anchor" href="#preguntas-frecuentes" aria-label="Permalink to &quot;Preguntas Frecuentes&quot;">​</a></h1><p>Este capítulo te ayuda a resolver diversos problemas que puedas encontrar al usar Plannotator. Ya sea puerto ocupado, navegador no abierto o fallos de integración, aquí encontrarás las soluciones correspondientes y técnicas de depuración.</p><h2 id="contenido-de-este-capitulo" tabindex="-1">Contenido de este capítulo <a class="header-anchor" href="#contenido-de-este-capitulo" aria-label="Permalink to &quot;Contenido de este capítulo&quot;">​</a></h2><div class="grid-cards"><a href="./common-problems/" class="card"><h3>🔧 Problemas comunes</h3><p>Resuelve problemas comunes durante el uso, incluyendo puerto ocupado, navegador no abierto, planes no mostrados, errores de Git, fallos al subir imágenes, problemas de integración con Obsidian/Bear, etc.</p></a><a href="./troubleshooting/" class="card"><h3>🔍 Solución de problemas</h3><p>Domina los métodos básicos de solución de problemas, incluyendo visualización de registros, manejo de errores y técnicas de depuración. Aprende a localizar rápidamente la fuente del problema a través de la salida de registros.</p></a></div><h2 id="ruta-de-aprendizaje" tabindex="-1">Ruta de aprendizaje <a class="header-anchor" href="#ruta-de-aprendizaje" aria-label="Permalink to &quot;Ruta de aprendizaje&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Problemas comunes → Solución de problemas</span></span>
<span class="line"><span>      ↓                   ↓</span></span>
<span class="line"><span>   Solución rápida    Depuración profunda</span></span></code></pre></div><p><strong>Orden recomendado</strong>:</p><ol><li><strong>Primero revisa problemas comunes</strong>: La mayoría de los problemas se pueden encontrar aquí con soluciones listas</li><li><strong>Luego aprende solución de problemas</strong>: Si los problemas comunes no cubren tu caso, aprende cómo diagnosticar por tu cuenta a través de registros y técnicas de depuración</li></ol><div class="tip custom-block"><p class="custom-block-title">Recomendación al encontrar problemas</p><p>Primero busca palabras clave en &quot;Problemas comunes&quot; (como &quot;puerto&quot;, &quot;navegador&quot;, &quot;Obsidian&quot;) para encontrar la solución correspondiente. Si el problema es complejo o no está en la lista, consulta &quot;Solución de problemas&quot; para aprender métodos de depuración.</p></div><h2 id="requisitos-previos" tabindex="-1">Requisitos previos <a class="header-anchor" href="#requisitos-previos" aria-label="Permalink to &quot;Requisitos previos&quot;">​</a></h2><p>Antes de estudiar este capítulo, se recomienda que hayas completado:</p><ul><li>✅ <a href="./../start/getting-started/">Inicio rápido</a> - Entiende los conceptos básicos de Plannotator</li><li>✅ Instalado el complemento Claude Code u OpenCode (elige uno): <ul><li><a href="./../start/installation-claude-code/">Instalar complemento Claude Code</a></li><li><a href="./../start/installation-opencode/">Instalar complemento OpenCode</a></li></ul></li></ul><h2 id="siguientes-pasos" tabindex="-1">Siguientes pasos <a class="header-anchor" href="#siguientes-pasos" aria-label="Permalink to &quot;Siguientes pasos&quot;">​</a></h2><p>Después de completar este capítulo, puedes continuar aprendiendo:</p><ul><li><a href="./../appendix/api-reference/">Referencia de API</a> - Conoce todos los endpoints de API y formatos de solicitud/respuesta</li><li><a href="./../appendix/data-models/">Modelos de datos</a> - Conoce las estructuras de datos que utiliza Plannotator</li><li><a href="./../advanced/environment-variables/">Configuración de variables de entorno</a> - Profundiza en todas las variables de entorno disponibles</li></ul>`,15)])])}const b=a(r,[["render",t]]);export{m as __pageData,b as default};
